import { useParams, Link } from 'react-router-dom';

const users = [
  { id: 101, name: "Rahul", email: "rahul@gmail.com", posts: ["Post 1", "Post 2"] },
  { id: 102, name: "Priya", email: "priya@gmail.com", posts: ["Post A", "Post B"] },
  { id: 103, name: "Arjun", email: "arjun@gmail.com", posts: ["Post X", "Post Y"] },
];

function UserProfile() {
  const { id } = useParams();
  const user = users.find(u => u.id === Number(id));

  if (!user) return <h2>User not found</h2>;

  return (
    <div>
      <Link to="/users">Back</Link>
      <h2>{user.name}</h2>
      <p>{user.email}</p>
      <ul>
        {user.posts.map((post, i) => <li key={i}>{post}</li>)}
      </ul>
    </div>
  );
}

export default UserProfile;